<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  html, body { height: 100%; overflow: hidden; }
  body {
    font-family: "Ubuntu", "Segoe UI", system-ui, sans-serif;
    color: #f2f2f2;
    user-select: none;
  }

  /* ---------- Desktop ---------- */
  #desktop {
    position: fixed;
    inset: 0;
    background:
      radial-gradient(ellipse at 30% 20%, #5a2d4d 0%, transparent 55%),
      radial-gradient(ellipse at 80% 80%, #772f2f 0%, transparent 55%),
      linear-gradient(135deg, #2c001e 0%, #3d1029 45%, #77216f 100%);
    overflow: hidden;
  }

  .desktop-hint {
    position: absolute;
    top: 60px;
    left: 24px;
    font-size: 13px;
    color: rgba(255,255,255,0.55);
    pointer-events: none;
    max-width: 240px;
    line-height: 1.5;
  }

  /* ---------- Top bar ---------- */
  #topbar {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 28px;
    background: rgba(0,0,0,0.75);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 13px;
    color: #ddd;
    z-index: 5000;
    backdrop-filter: blur(6px);
  }
  #topbar .activities { position: absolute; left: 14px; font-weight: 500; }
  #clock { position: absolute; right: 14px; font-variant-numeric: tabular-nums; }

  /* ---------- Taskbar / Dock ---------- */
  #taskbar {
    position: absolute;
    top: 40px;
    left: 10px;
    width: 60px;
    padding: 8px 6px;
    background: rgba(0,0,0,0.55);
    border-radius: 14px;
    display: flex;
    flex-direction: column;
    gap: 10px;
    z-index: 4000;
    backdrop-filter: blur(8px);
    box-shadow: 0 4px 20px rgba(0,0,0,0.4);
  }
  .launcher {
    width: 48px;
    height: 48px;
    border: none;
    border-radius: 12px;
    cursor: pointer;
    font-size: 24px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #fff;
    background: linear-gradient(160deg, #4a4a4a, #2b2b2b);
    transition: transform .12s ease, box-shadow .12s ease;
    position: relative;
  }
  .launcher:hover { transform: scale(1.08); box-shadow: 0 0 0 2px rgba(233,84,32,0.6); }
  .launcher:active { transform: scale(0.96); }
  .launcher.active::before {
    content: "";
    position: absolute;
    left: -6px;
    top: 50%;
    transform: translateY(-50%);
    width: 4px; height: 22px;
    border-radius: 3px;
    background: #e95420;
  }

  /* ---------- Windows ---------- */
  .window {
    position: absolute;
    min-width: 360px;
    min-height: 240px;
    background: #2b2b2b;
    border-radius: 10px;
    box-shadow: 0 12px 40px rgba(0,0,0,0.55);
    display: none;
    flex-direction: column;
    overflow: hidden;
    border: 1px solid rgba(255,255,255,0.08);
  }
  .window.open { display: flex; }

  .titlebar {
    height: 38px;
    background: linear-gradient(#3a3a3a, #303030);
    display: flex;
    align-items: center;
    padding: 0 10px;
    cursor: move;
    flex-shrink: 0;
    border-bottom: 1px solid rgba(0,0,0,0.4);
  }
  .titlebar .title { font-size: 13px; font-weight: 600; flex: 1; }
  .win-close {
    width: 22px; height: 22px;
    border: none;
    border-radius: 50%;
    background: #5a5a5a;
    color: #fff;
    cursor: pointer;
    font-size: 13px;
    line-height: 1;
    display: flex;
    align-items: center;
    justify-content: center;
  }
  .win-close:hover { background: #e95420; }

  /* ---------- Files app ---------- */
  #files-window { width: 640px; height: 440px; top: 90px; left: 140px; }
  .files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 10px;
    background: #333;
    border-bottom: 1px solid rgba(0,0,0,0.35);
    flex-shrink: 0;
  }
  #files-up {
    border: none;
    background: #4a4a4a;
    color: #fff;
    width: 30px; height: 30px;
    border-radius: 6px;
    cursor: pointer;
    font-size: 16px;
  }
  #files-up:hover { background: #e95420; }
  #files-path {
    flex: 1;
    background: #222;
    padding: 6px 10px;
    border-radius: 6px;
    font-family: "Ubuntu Mono", monospace;
    font-size: 13px;
    color: #9ee29e;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
  .files-body {
    flex: 1;
    overflow: auto;
    padding: 12px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(88px, 1fr));
    gap: 6px;
    align-content: start;
  }
  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
    padding: 10px 6px;
    border-radius: 8px;
    cursor: pointer;
    text-align: center;
    transition: background .1s;
  }
  .fs-item:hover { background: rgba(255,255,255,0.08); }
  .fs-item.selected { background: rgba(233,84,32,0.35); }
  .fs-item .icon { font-size: 34px; line-height: 1; }
  .fs-item .name {
    font-size: 12px;
    word-break: break-word;
    max-width: 84px;
  }

  /* ---------- Notepad app ---------- */
  #notepad-window { width: 560px; height: 420px; top: 130px; left: 300px; }
  #tabs {
    display: flex;
    align-items: stretch;
    background: #262626;
    border-bottom: 1px solid rgba(0,0,0,0.4);
    overflow-x: auto;
    flex-shrink: 0;
  }
  #tabs::-webkit-scrollbar { height: 5px; }
  .tab {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 8px 12px;
    font-size: 13px;
    cursor: pointer;
    border-right: 1px solid rgba(0,0,0,0.4);
    white-space: nowrap;
    color: #bbb;
    max-width: 160px;
  }
  .tab .tab-label { overflow: hidden; text-overflow: ellipsis; }
  .tab:hover { background: #303030; }
  .tab.active { background: #1e1e1e; color: #fff; box-shadow: inset 0 -2px 0 #e95420; }
  .tab .tab-close {
    border: none;
    background: transparent;
    color: #999;
    cursor: pointer;
    font-size: 14px;
    line-height: 1;
    border-radius: 50%;
    width: 16px; height: 16px;
  }
  .tab .tab-close:hover { background: #e95420; color: #fff; }
  #new-tab {
    border: none;
    background: transparent;
    color: #ccc;
    font-size: 20px;
    padding: 0 14px;
    cursor: pointer;
    flex-shrink: 0;
  }
  #new-tab:hover { color: #e95420; }
  #editor {
    flex: 1;
    border: none;
    resize: none;
    background: #1e1e1e;
    color: #eee;
    font-family: "Ubuntu Mono", monospace;
    font-size: 14px;
    line-height: 1.5;
    padding: 14px;
    outline: none;
    width: 100%;
  }
</style>
</head>
<body>
<div id="desktop">
  <div id="topbar">
    <span class="activities">Activities</span>
    <span>Ubuntu Desktop</span>
    <span id="clock">--:--</span>
  </div>

  <div class="desktop-hint">
    Welcome. Use the dock on the left to open Files or Notepad.
  </div>

  <div id="taskbar">
    <button id="open-files" class="launcher" title="Files">🗂️</button>
    <button id="open-notepad" class="launcher" title="Notepad">📝</button>
  </div>

  <!-- Files window -->
  <div id="files-window" class="window">
    <div class="titlebar">
      <span class="title">Files</span>
      <button class="win-close" title="Close">✕</button>
    </div>
    <div class="files-toolbar">
      <button id="files-up" title="Up">↑</button>
      <div id="files-path">/</div>
    </div>
    <div class="files-body" id="files-body"></div>
  </div>

  <!-- Notepad window -->
  <div id="notepad-window" class="window">
    <div class="titlebar">
      <span class="title">Notepad</span>
      <button class="win-close" title="Close">✕</button>
    </div>
    <div id="tabs"></div>
    <textarea id="editor" placeholder="Start typing…" spellcheck="false"></textarea>
  </div>
</div>

<script>
(function () {
  "use strict";

  /* ============ Clock ============ */
  var clockEl = document.getElementById("clock");
  function tick() {
    var d = new Date();
    var h = String(d.getHours()).padStart(2, "0");
    var m = String(d.getMinutes()).padStart(2, "0");
    clockEl.textContent = h + ":" + m;
  }
  tick();
  setInterval(tick, 10000);

  /* ============ Window management ============ */
  var zTop = 100;
  function focusWindow(win) { win.style.zIndex = ++zTop; }

  function bindWindow(win, launcher) {
    // Open
    launcher.addEventListener("click", function () {
      win.classList.add("open");
      launcher.classList.add("active");
      focusWindow(win);
    });
    // Close
    win.querySelector(".win-close").addEventListener("click", function () {
      win.classList.remove("open");
      launcher.classList.remove("active");
    });
    // Focus on click
    win.addEventListener("mousedown", function () { focusWindow(win); });
    // Drag by titlebar
    makeDraggable(win, win.querySelector(".titlebar"));
  }

  function makeDraggable(win, handle) {
    var dragging = false, offX = 0, offY = 0;
    handle.addEventListener("mousedown", function (e) {
      if (e.target.closest(".win-close")) return;
      dragging = true;
      var r = win.getBoundingClientRect();
      offX = e.clientX - r.left;
      offY = e.clientY - r.top;
      e.preventDefault();
    });
    document.addEventListener("mousemove", function (e) {
      if (!dragging) return;
      var x = e.clientX - offX;
      var y = e.clientY - offY;
      // keep within viewport, below top bar
      x = Math.max(0, Math.min(x, window.innerWidth - 80));
      y = Math.max(28, Math.min(y, window.innerHeight - 40));
      win.style.left = x + "px";
      win.style.top = y + "px";
    });
    document.addEventListener("mouseup", function () { dragging = false; });
  }

  bindWindow(document.getElementById("files-window"), document.getElementById("open-files"));
  bindWindow(document.getElementById("notepad-window"), document.getElementById("open-notepad"));

  /* ============ Files app ============ */
  // Static fake filesystem. Folders are objects, files are strings.
  var FS = {
    bin: { bash: "", ls: "", cat: "", grep: "", nano: "" },
    boot: { "vmlinuz-6.8.0": "", "initrd.img": "" },
    dev: { null: "", zero: "", sda1: "" },
    etc: {
      hostname: "",
      hosts: "",
      passwd: "",
      "fstab": "",
      apt: { "sources.list": "", "apt.conf": "" }
    },
    home: {
      user: {
        Documents: {
          "resume.pdf": "",
          "notes.txt": "",
          Projects: { "app.html": "", "README.md": "" }
        },
        Downloads: {
          "ubuntu-24.04.iso": "",
          "photo.jpg": ""
        },
        Pictures: {
          "wallpaper.png": "",
          "screenshot.png": ""
        },
        Music: { "song.mp3": "" },
        ".bashrc": "",
        ".profile": ""
      }
    },
    lib: { "libc.so.6": "", systemd: {} },
    media: { cdrom: {} },
    opt: {},
    proc: { cpuinfo: "", meminfo: "" },
    root: { ".bashrc": "" },
    sbin: { init: "", reboot: "" },
    tmp: { "session.lock": "" },
    usr: {
      bin: { python3: "", node: "", git: "" },
      lib: {},
      local: { bin: {} },
      share: { doc: {}, icons: {} }
    },
    var: {
      log: { "syslog": "", "auth.log": "" },
      cache: {},
      tmp: {},
      www: { html: { "index.html": "" } }
    }
  };

  var pathParts = []; // e.g. ["home","user"]
  var filesBody = document.getElementById("files-body");
  var filesPath = document.getElementById("files-path");

  function nodeAt(parts) {
    var node = FS;
    for (var i = 0; i < parts.length; i++) {
      if (node && typeof node === "object" && parts[i] in node) {
        node = node[parts[i]];
      } else {
        return null;
      }
    }
    return node;
  }

  function isFolder(v) { return v && typeof v === "object"; }

  function renderFiles() {
    var abs = "/" + pathParts.join("/");
    filesPath.textContent = pathParts.length ? abs : "/";
    filesBody.innerHTML = "";

    var node = nodeAt(pathParts);
    if (!isFolder(node)) return;

    var names = Object.keys(node).sort(function (a, b) {
      var fa = isFolder(node[a]), fb = isFolder(node[b]);
      if (fa !== fb) return fa ? -1 : 1;
      return a.localeCompare(b);
    });

    names.forEach(function (name) {
      var folder = isFolder(node[name]);
      var item = document.createElement("div");
      item.className = "fs-item";
      item.setAttribute("data-name", name);

      var icon = document.createElement("div");
      icon.className = "icon";
      icon.textContent = folder ? "📁" : fileIcon(name);

      var label = document.createElement("div");
      label.className = "name";
      label.textContent = name;

      item.appendChild(icon);
      item.appendChild(label);

      item.addEventListener("click", function () {
        filesBody.querySelectorAll(".fs-item.selected").forEach(function (el) {
          el.classList.remove("selected");
        });
        item.classList.add("selected");
      });

      item.addEventListener("dblclick", function () {
        if (folder) {
          pathParts.push(name);
          renderFiles();
        }
      });

      filesBody.appendChild(item);
    });
  }

  function fileIcon(name) {
    var n = name.toLowerCase();
    if (/\.(png|jpg|jpeg|gif|bmp)$/.test(n)) return "🖼️";
    if (/\.(mp3|wav|flac|ogg)$/.test(n)) return "🎵";
    if (/\.(txt|md|log|conf|list)$/.test(n)) return "📄";
    if (/\.(pdf)$/.test(n)) return "📕";
    if (/\.(iso|img)$/.test(n)) return "💿";
    if (/\.(html|htm|js|py|sh)$/.test(n)) return "📜";
    if (n[0] === ".") return "⚙️";
    return "📄";
  }

  document.getElementById("files-up").addEventListener("click", function () {
    if (pathParts.length) {
      pathParts.pop();
      renderFiles();
    }
  });

  renderFiles();

  /* ============ Notepad app ============ */
  var STORE_KEY = "ubuntu_notepad_state_v1";
  var tabsEl = document.getElementById("tabs");
  var editor = document.getElementById("editor");

  var state = loadState();

  function loadState() {
    try {
      var raw = localStorage.getItem(STORE_KEY);
      if (raw) {
        var s = JSON.parse(raw);
        if (s && Array.isArray(s.tabs) && s.tabs.length) {
          if (typeof s.active !== "number" || s.active < 0 || s.active >= s.tabs.length) {
            s.active = 0;
          }
          return s;
        }
      }
    } catch (e) {}
    return { tabs: [{ title: "Untitled", content: "" }], active: 0, seq: 1 };
  }

  function saveState() {
    try { localStorage.setItem(STORE_KEY, JSON.stringify(state)); } catch (e) {}
  }

  function renderTabs() {
    tabsEl.innerHTML = "";
    state.tabs.forEach(function (tab, idx) {
      var el = document.createElement("div");
      el.className = "tab" + (idx === state.active ? " active" : "");

      var label = document.createElement("span");
      label.className = "tab-label";
      label.textContent = tab.title || "Untitled";

      var close = document.createElement("button");
      close.className = "tab-close";
      close.textContent = "✕";
      close.title = "Close tab";
      close.addEventListener("click", function (e) {
        e.stopPropagation();
        closeTab(idx);
      });

      el.appendChild(label);
      el.appendChild(close);

      el.addEventListener("click", function () {
        state.active = idx;
        syncEditor();
        renderTabs();
        saveState();
      });

      tabsEl.appendChild(el);
    });

    // add-new-tab button
    var add = document.createElement("button");
    add.id = "new-tab";
    add.textContent = "+";
    add.title = "New tab";
    add.addEventListener("click", newTab);
    tabsEl.appendChild(add);
  }

  function syncEditor() {
    var tab = state.tabs[state.active];
    editor.value = tab ? tab.content : "";
  }

  function newTab() {
    state.seq = (state.seq || 1) + 1;
    state.tabs.push({ title: "Untitled " + state.seq, content: "" });
    state.active = state.tabs.length - 1;
    syncEditor();
    renderTabs();
    saveState();
    editor.focus();
  }

  function closeTab(idx) {
    state.tabs.splice(idx, 1);
    if (state.tabs.length === 0) {
      state.tabs.push({ title: "Untitled", content: "" });
      state.active = 0;
    } else if (state.active >= state.tabs.length) {
      state.active = state.tabs.length - 1;
    } else if (idx < state.active) {
      state.active--;
    }
    syncEditor();
    renderTabs();
    saveState();
  }

  editor.addEventListener("input", function () {
    var tab = state.tabs[state.active];
    if (!tab) return;
    tab.content = editor.value;
    // derive title from first non-empty line
    var firstLine = editor.value.split("\n")[0].trim();
    tab.title = firstLine ? firstLine.slice(0, 20) : "Untitled";
    // update label live without full re-render
    var activeTabEl = tabsEl.querySelectorAll(".tab")[state.active];
    if (activeTabEl) {
      activeTabEl.querySelector(".tab-label").textContent = tab.title;
    }
    saveState();
  });

  document.getElementById("open-notepad").addEventListener("click", function () {
    syncEditor();
    renderTabs();
  });

  renderTabs();
  syncEditor();
})();
</script>
</body>
</html>
